import{_ as a,c as t,o as n,ak as i,ao as o}from"./chunks/framework.DHLlVITf.js";const g=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-118-0.md","filePath":"aireblock-releases/aireglu-v1-118-0.md","lastUpdated":1783505425000}'),s={name:"aireblock-releases/aireglu-v1-118-0.md"};function r(l,e,c,d,u,h){return n(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+o+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.118.0<br><strong>Release Date:</strong> 1st July 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Email Connector Support for Send Email Tasks — GLU-3094, GLU-3136, GLU-3158, GLU-3171</li><li>Reorganised Email Task Authorisation Settings — GLU-3096</li><li>Agent Token Usage Tracking by Tenant — GLU-2962</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Endpoint Name Validation Now Consistent — GLU-3137</li><li>Prevent Self-Referencing Endpoint Task Loops — GLU-3138</li><li>Route Mapping Create Error — GLU-3165</li><li>Adapter Executor No Longer Fails on Extra Parameters — GLU-3179</li><li>Email Task Attachment Upload Fixed — GLU-3186</li><li>Fixed Metric Properties - GLU-3107</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="email-connector-support-for-send-email-tasks-glu-3094-glu-3136-glu-3158-glu-3171" tabindex="-1">Email Connector Support for Send Email Tasks (GLU-3094, GLU-3136, GLU-3158, GLU-3171) <a class="header-anchor" href="#email-connector-support-for-send-email-tasks-glu-3094-glu-3136-glu-3158-glu-3171" aria-label="Permalink to “Email Connector Support for Send Email Tasks (GLU-3094, GLU-3136, GLU-3158, GLU-3171)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireGlu now supports linking email tasks directly to an email connection, including Office 365 connections via the Microsoft Graph API. You can configure a named email connection at the task level or set one as the tenant-wide default for all email sending. The tenant settings page has been updated to let you choose between the AireGlu default sender, custom SMTP, or a specific email connection. Connections marked as the tenant default are protected from deletion via both the API and the UI.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now send emails through your organisation&#39;s Office 365 account or other configured email services, rather than relying solely on SMTP credentials. Set a preferred connection once at the tenant level and all email tasks will use it automatically, or override it per task as needed. If a connection is set as the default, you won&#39;t accidentally delete it.</p></div><h4 id="reorganised-email-task-authorisation-settings-glu-3096" tabindex="-1">Reorganised Email Task Authorisation Settings (GLU-3096) <a class="header-anchor" href="#reorganised-email-task-authorisation-settings-glu-3096" aria-label="Permalink to “Reorganised Email Task Authorisation Settings (GLU-3096)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The SMTP configuration fields within the email task editor have been moved from the main settings into a dedicated Authorisation tab. The authentication type is now selected from a dropdown, offering options for the tenant default, custom SMTP credentials, or an email connection link.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Email task configuration is now cleaner and easier to navigate. Authentication settings are grouped together in their own tab, making it straightforward to see and change how each email task is authorised to send.</p></div><h4 id="agent-token-usage-tracking-by-tenant-glu-2962" tabindex="-1">Agent Token Usage Tracking by Tenant (GLU-2962) <a class="header-anchor" href="#agent-token-usage-tracking-by-tenant-glu-2962" aria-label="Permalink to “Agent Token Usage Tracking by Tenant (GLU-2962)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireGlu now records agent token usage metrics per tenant and environment. This data will be used to support usage-based pricing and cost analysis across tenants.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your organisation&#39;s AI agent usage is now tracked at the tenant level, providing the foundation for accurate usage reporting and cost transparency as AireGlu&#39;s agent capabilities expand.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="endpoint-name-validation-now-consistent-glu-3137" tabindex="-1">Endpoint Name Validation Now Consistent (GLU-3137) <a class="header-anchor" href="#endpoint-name-validation-now-consistent-glu-3137" aria-label="Permalink to “Endpoint Name Validation Now Consistent (GLU-3137)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The frontend and backend validation rules for endpoint names were out of sync, meaning a user could configure an endpoint with an invalid name (such as one containing an underscore) and only encounter an error on save — without a clear explanation. Frontend validation now matches the backend rules, so invalid names are flagged immediately when entered.</p></div><h4 id="prevent-self-referencing-endpoint-task-loops-glu-3138" tabindex="-1">Prevent Self-Referencing Endpoint Task Loops (GLU-3138) <a class="header-anchor" href="#prevent-self-referencing-endpoint-task-loops-glu-3138" aria-label="Permalink to “Prevent Self-Referencing Endpoint Task Loops (GLU-3138)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When using an AireGlu Endpoint task, the dropdown list of endpoints to call no longer includes the endpoint currently being edited. This prevents accidental recursive configurations that could result in infinite loops at runtime.</p></div><h4 id="route-mapping-create-error-glu-3165" tabindex="-1">Route Mapping Create Error (GLU-3165) <a class="header-anchor" href="#route-mapping-create-error-glu-3165" aria-label="Permalink to “Route Mapping Create Error (GLU-3165)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Creating a new route mapping was incorrectly returning an error to the user even though the record was saving successfully in the background. This been resolved so that route mappings now save and confirm correctly without requiring a page refresh.</p></div><h4 id="email-task-attachment-upload-fixed-glu-3186" tabindex="-1">Email Task Attachment Upload Fixed (GLU-3186) <a class="header-anchor" href="#email-task-attachment-upload-fixed-glu-3186" aria-label="Permalink to “Email Task Attachment Upload Fixed (GLU-3186)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When uploading a file attachment via the email task&#39;s Advanced Settings tab, the Base64 value being stored incorrectly included the file metadata prefix (e.g. <code>data:text/plain;base64,</code>) rather than the raw encoded content. This caused the attachment to arrive with corrupted content. The metadata prefix is now stripped so only the correct Base64 data is stored and sent.</p></div><h4 id="adapter-executor-no-longer-fails-on-extra-parameters-glu-3179" tabindex="-1">Adapter Executor No Longer Fails on Extra Parameters (GLU-3179) <a class="header-anchor" href="#adapter-executor-no-longer-fails-on-extra-parameters-glu-3179" aria-label="Permalink to “Adapter Executor No Longer Fails on Extra Parameters (GLU-3179)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Previously, if the data passed to an adapter executor contained additional fields beyond those defined in the adapter&#39;s value schema, the execution would fail with a validation error. Extra parameters are now treated as a warning rather than an error, allowing adapters to run successfully while logging unexpected fields for review.</p></div><h3 id="url-in-the-metrics-should-wrap-and-not-cause-a-scrollbar" tabindex="-1">URL in the Metrics, should wrap and not cause a scrollbar <a class="header-anchor" href="#url-in-the-metrics-should-wrap-and-not-cause-a-scrollbar" aria-label="Permalink to “URL in the Metrics, should wrap and not cause a scrollbar”">​</a></h3><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed metrics properties (URL, status code, success status) not displaying on the metrics page for certain endpoint task behaviours such as HTTP Request tasks, and wrapped long URLs to prevent horizontal scrolling.</p></div>',34)])])}const m=a(s,[["render",r]]);export{g as __pageData,m as default};
